+type Heading = {level: number, text: string, anchor: string};
+
+const tocStartRegex = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEndRegex = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeadingRegex = /^(?: {0,3})(#{1,6})[ \	]+(.+?)\\s*$/;
+const explicitIdRegex = /\\s+\\{#([^}\\s]+)\\}\\s*$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startIndex = lines.findIndex((line) => tocStartRegex.test(line));
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(startIndex + 1).findIndex((line) => tocEndRegex.test(line));
+    const endIndex = endOffset === -1 ? -1 : startIndex + endOffset + 1;
+    const tocEnd = endIndex === -1 ? lines.length : endIndex;
+    const headings = this.getHeadings(lines, startIndex, tocEnd, options);
+    const tocLines = this.buildToc(headings, options);
+    const title = options.title.trim();
+    const prefix = lines.slice(0, startIndex);
+    const suffix = endIndex === -1 ? [] : lines.slice(endIndex + 1).filter((line, index, array) => index > 0 || line !== '' || array.length === 1);
+
+    // The generated region owns its surrounding blank lines. Remove leading
+    // empty suffix lines so it always has exactly one blank line after it.
+    while (suffix[0] === '') {
+      suffix.shift();
+    }
+
+    const region = [
+      lines[startIndex],
+      '',
+      ...(title ? [title, ''] : []),
+      ...tocLines,
+      '',
+      endIndex === -1 ? '<!-- /toc -->' : lines[endIndex],
+      '',
+    ];
+
+    return [...prefix, ...region, ...suffix].join('\
');
+  }
+
+  private getHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const anchorCounts = new Map<string, number>();
+    let inYaml = lines[0]?.trim() === '---';
+    let fence: string = null;
+    let mathDelimiter: string = null;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (inYaml) {
+        if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) {
+          inYaml = false;
+        }
+        continue;
+      }
+
+      const fenceMatch = line.match(/^ {0,3}(`{3,}|~{3,})/);
+      if (fenceMatch) {
+        if (fence === null) {
+          fence = fenceMatch[1][0];
+        } else if (fence === fenceMatch[1][0]) {
+          fence = null;
+        }
+        continue;
+      }
+      if (fence !== null) {
+        continue;
+      }
+
+      if (/^\\s*\\$\\$\\s*$/.test(line) || /^\\s*\\\\\\[\\s*$/.test(line)) {
+        const delimiter = line.trim();
+        mathDelimiter = mathDelimiter === null ? delimiter : null;
+        continue;
+      }
+      if (mathDelimiter !== null) {
+        continue;
+      }
+
+      if (index > tocStart && index < tocEnd) {
+        continue;
+      }
+
+      const match = line.match(atxHeadingRegex);
+      if (!match) {
+        continue;
+      }
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) {
+        continue;
+      }
+
+      let headingText = match[2].replace(/\\s+#+\\s*$/, '');
+      const explicitId = headingText.match(explicitIdRegex);
+      if (explicitId) {
+        headingText = headingText.slice(0, explicitId.index).trimEnd();
+      }
+      const displayText = this.resolveLinks(headingText);
+      if (this.isExcluded(headingText, displayText, options.excludeHeadings)) {
+        continue;
+      }
