+      const baseAnchor = options.useExplicitIds && explicitId ? explicitId[1] : this.toAnchor(displayText);
+      const seen = anchorCounts.get(baseAnchor) ?? 0;
+      anchorCounts.set(baseAnchor, seen + 1);
+      const anchor = seen === 0 ? baseAnchor : `${baseAnchor}-${seen}`;
+      headings.push({
+        level,
+        text: options.stripFormattingInToc ? this.stripFormatting(displayText) : displayText,
+        anchor,
+      });
+    }
+
+    return headings;
+  }
+
+  private buildToc(headings: Heading[], options: AutoTocOptions): string[] {
+    return headings.map((heading, index) => {
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'number' ?
+        `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      return `${indent}${marker} [${heading.text}](#${heading.anchor})`;
+    });
+  }
