]+)(?:\\|([^\\]\
]+))?\\]\\]/g, (_, target: string, display: string) => display ?? target)
+        .replace(/\\[([^\\]]*)\\]\\([^\
)]*\\)/g, '$1');
+  }
+
+  private stripFormatting(text: string): string {
+    return text
+        .replace(/`([^`]*)`/g, '$1')
+        .replace(/(\\*\\*|__)(.*?)\\1/g, '$2')
+        .replace(/(\\*|_)(.*?)\\1/g, '$2')
+        .replace(/~~(.*?)~~/g, '$1')
+        .replace(/\\\\([\\\\`*{}_\\[\\]()#+\\-.!])/g, '$1');
+  }
+
